const b = $input.first().json.body ?? $input.first().json;
const task = b.task ?? 'generate';
let system = `You are ShipLog AI, a build-in-public writer for founders. Sound like a real founder, never like AI. No 'exciting news' openers. Be specific, use their real event data, include numbers. Tweets max 280 chars or thread format. LinkedIn 800-1200 chars.`;
let user = '';
if (task === 'chat') {
  system = `You are the ShipLog Co-pilot for a founder building ${b.projectName}. You have their full shipping log. Be a real companion: specific, warm, brief (2-4 sentences), reference actual events by name and date. Motivate with receipts, never generic hype.`;
  user = `Streak: ${b.streak} days.
Recent events:
${(b.events??[]).map(e=>`- ${e.date} [${e.category}] ${e.title}`).join('
')}

Reflections:
${(b.dailyLogs??[]).map(l=>`${l.date}: built ${l.built}; learned ${l.learned}`).join('
')}

Question: ${b.question}`;
} else if (task === 'humanize') {
  user = `Project: ${b.projectName}
Platform: ${b.platform}
Voice: ${b.tone}

Raw notes from the builder:
${b.raw}

Shape this into a post. Keep their facts and voice. It must read like a human typed it.`;
} else if (task === 'fuse') {
  user = `Project: ${b.projectName}
Platform: ${b.platform}
Voice: ${b.tone}

Ships picked from the log:
${(b.picked??[]).map(e=>`- [${e.category}] ${e.title} (${e.date})`).join('
')}

Their current state, raw:
${b.state}

Fuse the logged facts with the human feeling into one post.`;
} else {
  user = `Project: ${b.projectName} — ${b.projectTagline}
Platform: ${b.platform}
Voice: ${b.tone}

Events:
${(b.events??[]).map(e=>`- [${e.category}] ${e.title} (${e.date})`).join('
')}

Reflections:
${(b.dailyLogs??[]).map(l=>`${l.date}: built ${l.built}; learned ${l.learned}`).join('
')}

Write the ${b.platform} post in ${b.tone} voice.`;
}
return [{ json: { system, user } }];
